import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import './app.css';
import AICoach from './components/AICoach';
import Therapy from './components/Therapy';
import Community from './components/Community';
import Report from './components/Report';
import Profile from './components/Profile';
import Chat from './components/Chat';
import DoctorDashboard from './components/DoctorDashboard';
import DoctorLogin from './components/DoctorLogin';
import PatientLogin from './components/PatientLogin';
import Onboarding from './components/Onboarding';

const MoodMate = () => {
  const [activeTab, setActiveTab] = useState('chat');
  const [showOnboarding, setShowOnboarding] = useState(!localStorage.getItem('moodmate_onboarded'));
  
  // ── Doctor Portal Role Switch ──
  const [doctorMode, setDoctorMode] = useState(() => {
    const s = localStorage.getItem('moodmate_doctor_session');
    return s ? JSON.parse(s) : null;
  });
  const [showDoctorLogin, setShowDoctorLogin] = useState(false);

  const handleDoctorLogin = (doc) => {
    setDoctorMode(doc);
    setShowDoctorLogin(false);
  };
  const handleDoctorLogout = () => {
    localStorage.removeItem('moodmate_doctor_session');
    setDoctorMode(null);
    setShowDoctorLogin(false);
  };
  // ── Patient User Session ──
  const [user, setUser] = useState(() => {
    const s = localStorage.getItem('moodmate_user');
    return s ? JSON.parse(s) : null;
  });

  const handlePatientLogin = (loggedInUser) => {
    localStorage.setItem('moodmate_user', JSON.stringify(loggedInUser));
    setUser(loggedInUser);
  };
  
  const [showNotifications, setShowNotifications] = useState(false);
  const [notifications] = useState([
    { id: 0, text: `Kal tum ${user?.lastMood || 'calm'} feel kar rahe the... aaj usse behtar feel karne ka waqt hai. Breathe? 🧘`, time: "Just now", unread: true, memory: true },
    { id: 1, text: "5 coins earned for your check-in!", time: "2m ago", unread: true },
    { id: 2, text: "Someone reacted to your Tribe post", time: "1h ago", unread: false },
    { id: 3, text: "Your Weekly Report is ready", time: "3h ago", unread: false }
  ]);

  const handleOnboardingComplete = () => {
    localStorage.setItem('moodmate_onboarded', 'true');
    setShowOnboarding(false);
  };

  // Sync Global User State with Backend
  useEffect(() => {
    if (!user) return;
    const fetchUserStatus = async () => {
      try {
        const response = await fetch(`http://localhost:5000/api/user/status?user_id=${user.id}`);
        const data = await response.json();
        if (data.status === 'success') {
          setUser(prev => ({
            ...prev,
            streak: data.streak || 1,
            lastMood: data.last_mood || 'neutral',
            coins: data.coins || 0
          }));
        }
      } catch (err) {
        console.error("Sync failed:", err);
      }
    };
    fetchUserStatus();
  }, [user?.id]);
  
  // ── Rendering flow ──

  // 1. Doctor Login screen (full-page takeover)
  if (showDoctorLogin && !doctorMode) {
    return <DoctorLogin onLoginSuccess={handleDoctorLogin} onBackToApp={() => setShowDoctorLogin(false)} />;
  }

  // 2. Doctor Dashboard (full-page, no patient nav)
  if (doctorMode) {
    return (
      <div className="app-container">
        {/* Minimal doctor header */}
        <header className="app-header" style={{ background: 'linear-gradient(135deg,#1e1b4b,#4f46e5)' }}>
          <div className="header-left">
            <h1 style={{ color: 'white' }}>MoodMate</h1>
            <span style={{ fontSize: '12px', background: 'rgba(255,255,255,0.15)', color: 'rgba(255,255,255,0.8)', padding: '4px 12px', borderRadius: '20px', fontWeight: '700', letterSpacing: '0.08em', textTransform: 'uppercase' }}>
              🩺 Doctor Portal
            </span>
          </div>
          <div className="header-right" style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
              <div style={{ width: '34px', height: '34px', borderRadius: '10px', background: doctorMode.palette || 'linear-gradient(135deg,#4f46e5,#7c3aed)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: '900', fontSize: '12px', color: 'white', border: '2px solid rgba(255,255,255,0.25)' }}>
                {doctorMode.initials}
              </div>
              <div style={{ color: 'white' }}>
                <div style={{ fontSize: '13px', fontWeight: '700' }}>{doctorMode.name}</div>
                <div style={{ fontSize: '11px', opacity: 0.65 }}>{doctorMode.spec}</div>
              </div>
            </div>
            <button
              onClick={handleDoctorLogout}
              style={{ padding: '8px 16px', background: 'rgba(255,255,255,0.12)', border: '1px solid rgba(255,255,255,0.2)', borderRadius: '10px', color: 'white', fontSize: '12px', fontWeight: '700', cursor: 'pointer', fontFamily: 'Inter,sans-serif', transition: 'all 0.2s' }}
              onMouseOver={e => e.currentTarget.style.background='rgba(255,255,255,0.2)'}
              onMouseOut={e => e.currentTarget.style.background='rgba(255,255,255,0.12)'}
            >
              Sign Out
            </button>
          </div>
        </header>
        <main className="app-main">
          <DoctorDashboard doctor={doctorMode} />
        </main>
      </div>
    );
  }

  // 3. Patient Login screen (if no user session)
  if (!user) {
    return <PatientLogin onLoginSuccess={handlePatientLogin} />;
  }

  // 4. Main Patient Dashboard/App
  return (
    <div className="app-container">
      <AnimatePresence>
        {showOnboarding && <Onboarding onComplete={handleOnboardingComplete} />}
      </AnimatePresence>
      <AnimatePresence>
        {/* Header */}
      <header className="app-header">
          <div className="header-left">
            <h1>MoodMate</h1>
            <div className="nav-tabs">
              {[
                { id: 'chat', icon: '💬', label: 'Chat' },
                { id: 'ai-coach', icon: '🤖', label: 'AI Coach' },
                { id: 'therapy', icon: '👨‍⚕️', label: 'Therapy' },
                { id: 'community', icon: '🌍', label: 'Community' },
                { id: 'report', icon: '📊', label: 'Report' },
              ].map(tab => (
                <button 
                  key={tab.id}
                  className={activeTab === tab.id ? 'nav-tab active' : 'nav-tab'}
                  onClick={() => setActiveTab(tab.id)}
                >
                  {tab.icon} {tab.label}
                </button>
              ))}
            </div>
          </div>
          <div className="header-right" style={{ display: 'flex', alignItems: 'center', gap: '16px', position: 'relative' }}>
            {/* Live streak + coins pill */}
            {(user.streak > 0 || user.coins > 0) && (
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px', background: '#f8fafc', borderRadius: '20px', padding: '6px 14px', border: '1px solid #e2e8f0' }}>
                <span style={{ fontSize: '13px', color: '#64748b', fontWeight: '600' }}>🔥 {user.streak || 0}</span>
                <span style={{ width: '1px', height: '14px', background: '#e2e8f0' }}></span>
                <span style={{ fontSize: '13px', color: '#64748b', fontWeight: '600' }}>🪙 {user.coins || 0}</span>
              </div>
            )}

            {/* Notification Bell */}
            <div 
              style={{ position: 'relative', cursor: 'pointer', padding: '8px', borderRadius: '50%', background: showNotifications ? '#f1f5f9' : 'transparent' }} 
              onClick={() => setShowNotifications(!showNotifications)}
              title="Notifications"
            >
               <svg width="22" height="22" viewBox="0 0 24 24" fill="none" stroke={showNotifications ? "#4F46E5" : "#64748b"} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"></path>
                  <path d="M13.73 21a2 2 0 0 1-3.46 0"></path>
               </svg>
               <div style={{ position: 'absolute', top: '6px', right: '6px', width: '8px', height: '8px', background: '#ef4444', borderRadius: '50%', border: '2px solid white' }}></div>
               
               <AnimatePresence>
                 {showNotifications && (
                   <motion.div 
                     initial={{ opacity: 0, y: 10, scale: 0.95 }}
                     animate={{ opacity: 1, y: 0, scale: 1 }}
                     exit={{ opacity: 0, y: 10, scale: 0.95 }}
                     style={{ position: 'absolute', top: '48px', right: '0', width: '280px', background: 'white', borderRadius: '16px', boxShadow: '0 15px 40px rgba(0,0,0,0.15)', border: '1px solid #e2e8f0', zIndex: 2000, overflow: 'hidden' }}
                     onClick={e => e.stopPropagation()}
                   >
                      <div style={{ padding: '14px 16px', borderBottom: '1px solid #f1f5f9', fontWeight: 'bold', fontSize: '14px', display: 'flex', justifyContent: 'space-between' }}>
                        <span>Notifications</span>
                        <span style={{ color: '#4F46E5', fontSize: '12px', cursor: 'pointer' }}>Mark all read</span>
                      </div>
                      <div style={{ maxHeight: '280px', overflowY: 'auto' }}>
                        {notifications.map(n => (
                          <div key={n.id} style={{ padding: '12px 16px', borderBottom: '1px solid #f8fafc', background: n.unread ? 'rgba(79, 70, 229, 0.03)' : 'transparent' }}>
                            <div style={{ fontSize: '13px', color: '#0f172a', marginBottom: '3px' }}>{n.text}</div>
                            <div style={{ fontSize: '11px', color: '#94a3b8' }}>{n.time}</div>
                          </div>
                        ))}
                      </div>
                   </motion.div>
                 )}
               </AnimatePresence>
            </div>
            
            {/* Avatar — goes to Profile */}
            <div 
              onClick={() => setActiveTab('profile')}
              style={{ width: '38px', height: '38px', borderRadius: '50%', background: 'linear-gradient(135deg, #FF007F, #7000FF)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontWeight: 'bold', fontSize: '15px', cursor: 'pointer', boxShadow: '0 4px 15px rgba(112,0,255,0.25)', transition: 'transform 0.2s', flexShrink: 0 }} 
              onMouseOver={e => e.currentTarget.style.transform='scale(1.08)'} 
              onMouseOut={e => e.currentTarget.style.transform='scale(1)'}
              title="Profile & Settings"
            >
              {user.username.charAt(0).toUpperCase()}
            </div>
          </div>
        </header>

        <main className="app-main">
          <AnimatePresence mode="wait">
            <motion.div
              key={activeTab}
              initial={{ opacity: 0, y: 15 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.98 }}
              transition={{ duration: 0.3, ease: 'easeOut' }}
              style={{ width: '100%', height: '100%' }}
            >
              {activeTab === 'chat' && <Chat user={user} />}
              {activeTab === 'ai-coach' && <AICoach user={user} />}
              {activeTab === 'therapy' && <Therapy user={user} />}
              {activeTab === 'community' && <Community user={user} />}
              {activeTab === 'report' && <Report user={user} />}
              {activeTab === 'profile' && <Profile user={user} onLogout={() => { localStorage.clear(); window.location.reload(); }} />}
            </motion.div>
          </AnimatePresence>
        </main>
      </AnimatePresence>

      {/* Floating Action Button for Grounding */}
      <motion.button
        className="floating-breathe-btn"
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        onClick={() => setActiveTab('ai-coach')}
        title="Immediate Grounding"
      >
        🧘
      </motion.button>

      {/* Hidden Doctor Portal Access Link */}
      <button
        onClick={() => setShowDoctorLogin(true)}
        style={{
          position: 'fixed', bottom: '14px', left: '50%',
          transform: 'translateX(-50%)',
          background: 'none', border: 'none',
          fontSize: '11px', color: '#c4b5fd',
          cursor: 'pointer', fontFamily: 'Inter,sans-serif',
          fontWeight: '600', opacity: 0.6, transition: 'opacity 0.2s',
          letterSpacing: '0.03em',
        }}
        onMouseOver={e => e.currentTarget.style.opacity = '1'}
        onMouseOut={e => e.currentTarget.style.opacity = '0.6'}
        title="Healthcare Professional Portal"
      >
        🩺 Healthcare Professional Sign In
      </button>
    </div>
  );
};

export default MoodMate;
